+IPluginV2DynamicExt *IntMulBoolPlugin::clone() const noexcept
+{
+    WHERE_AM_I();
+    auto p = new IntMulBoolPlugin(name_);
+    p->setPluginNamespace(namespace_.c_str());
+    return p;
+}
