+template<typename T>
+__global__ void addScalarKernel(const T *input, T *output, const T scalar, const int nElement)
+{
+    const int index = blockIdx.x * blockDim.x + threadIdx.x;
+    if (index >= nElement)
+        return;
+        
+    T _1          = input[index];
+    T _2          = _1 + scalar;
+    output[index] = _2;
+}
