+{
+    WHERE_AM_I()
+    if (inOut[pos].format != TensorFormat::kLINEAR)
+        return false;
+
+    switch (pos)
+    {
+    case 0:
+        return inOut[0].type == DataType::kFLOAT || inOut[0].type == DataType::kHALF;
