+        std::cout << __FUNCTION__ << std::endl;
+        int batch_dims = 0;
+        for (int i = 0; i < fc->nbFields; i++) {
+            if (!strcmp(fc->fields[i].name, "batch_dims")) {
+                batch_dims = *(int *)fc->fields[i].data;
+            }
+        }
